import{_ as o,c as e,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Integração com Bear: Salvar Planos Automaticamente | Plannotator","description":"Aprenda a configurar a integração do Plannotator com o Bear. Salve planos aprovados automaticamente via x-callback-url, gere tags inteligentes e construa sua base de conhecimento.","frontmatter":{"title":"Integração com Bear: Salvar Planos Automaticamente | Plannotator","sidebarTitle":"Salvar Planos no Bear","subtitle":"Integração com Bear: Salvar Planos Aprovados Automaticamente | Plannotator","description":"Aprenda a configurar a integração do Plannotator com o Bear. Salve planos aprovados automaticamente via x-callback-url, gere tags inteligentes e construa sua base de conhecimento.","tags":["Integração","Bear","Aplicativo de Notas","Base de Conhecimento"],"prerequisite":["installation-claude-code","platforms-plan-review-basics"],"order":3},"headers":[],"relativePath":"pt/backnotprop/plannotator/advanced/bear-integration/index.md","filePath":"pt/backnotprop/plannotator/advanced/bear-integration/index.md"}'),i={name:"pt/backnotprop/plannotator/advanced/bear-integration/index.md"};function n(s,a,l,d,c,p){return t(),e("div",null,[...a[0]||(a[0]=[r(`<h1 id="integracao-com-bear-salvar-planos-aprovados-automaticamente" tabindex="-1">Integração com Bear: Salvar Planos Aprovados Automaticamente <a class="header-anchor" href="#integracao-com-bear-salvar-planos-aprovados-automaticamente" aria-label="Permalink to &quot;Integração com Bear: Salvar Planos Aprovados Automaticamente&quot;">​</a></h1><h2 id="o-que-voce-vai-aprender" tabindex="-1">O Que Você Vai Aprender <a class="header-anchor" href="#o-que-voce-vai-aprender" aria-label="Permalink to &quot;O Que Você Vai Aprender&quot;">​</a></h2><p>Com a integração Bear ativada, cada vez que você aprovar um plano, o Plannotator salvará automaticamente no seu Bear, incluindo:</p><ul><li>Título gerado automaticamente (extraído do plano)</li><li>Tags inteligentes (nome do projeto, palavras-chave, linguagens de programação)</li><li>Conteúdo completo do plano</li></ul><p>Assim você pode gerenciar todos os planos aprovados em um só lugar, facilitando consultas futuras e a construção da sua base de conhecimento.</p><h2 id="o-problema-que-voce-enfrenta" tabindex="-1">O Problema Que Você Enfrenta <a class="header-anchor" href="#o-problema-que-voce-enfrenta" aria-label="Permalink to &quot;O Problema Que Você Enfrenta&quot;">​</a></h2><p>Você provavelmente já passou por estas situações:</p><ul><li>O plano gerado pela IA é ótimo, mas você quer salvá-lo para referência futura</li><li>Copiar e colar planos manualmente no Bear é tedioso</li><li>Planos de diferentes projetos ficam misturados, sem organização por tags</li></ul><p>Com a integração Bear, todos esses problemas são resolvidos automaticamente.</p><h2 id="quando-usar-este-recurso" tabindex="-1">Quando Usar Este Recurso <a class="header-anchor" href="#quando-usar-este-recurso" aria-label="Permalink to &quot;Quando Usar Este Recurso&quot;">​</a></h2><ul><li>Você usa o Bear como seu principal aplicativo de notas</li><li>Precisa arquivar planos aprovados como base de conhecimento</li><li>Quer encontrar rapidamente planos anteriores através de tags</li></ul><div class="info custom-block"><p class="custom-block-title">Sobre o Bear</p><p>Bear é um aplicativo de notas Markdown para macOS que suporta tags, criptografia, sincronização e muito mais. Se você ainda não o instalou, visite <a href="https://bear.app/" target="_blank" rel="noreferrer">bear.app</a> para saber mais.</p></div><h2 id="🎒-antes-de-comecar" tabindex="-1">🎒 Antes de Começar <a class="header-anchor" href="#🎒-antes-de-comecar" aria-label="Permalink to &quot;🎒 Antes de Começar&quot;">​</a></h2><ul><li>Plannotator instalado (veja o <a href="./../../start/installation-claude-code/">tutorial de instalação</a>)</li><li>Bear instalado e funcionando normalmente</li><li>Familiaridade com o fluxo básico de revisão de planos (veja <a href="./../../platforms/plan-review-basics/">Fundamentos da Revisão de Planos</a>)</li></ul><h2 id="conceito-principal" tabindex="-1">Conceito Principal <a class="header-anchor" href="#conceito-principal" aria-label="Permalink to &quot;Conceito Principal&quot;">​</a></h2><p>O núcleo da integração Bear é o protocolo <strong>x-callback-url</strong>:</p><ol><li>Ative a integração Bear na interface do Plannotator (armazenado no localStorage do navegador)</li><li>Ao aprovar um plano, o Plannotator envia uma URL <code>bear://x-callback-url/create</code></li><li>O sistema usa o comando <code>open</code> para abrir automaticamente o Bear e criar a nota</li><li>Conteúdo do plano, título e tags são preenchidos automaticamente</li></ol><p><strong>Características principais</strong>:</p><ul><li>Não precisa configurar caminho do vault (diferente do Obsidian)</li><li>Tags geradas inteligentemente (máximo de 7)</li><li>Salvamento automático ao aprovar o plano</li></ul><div class="tip custom-block"><p class="custom-block-title">Diferença em Relação ao Obsidian</p><p>A integração Bear é mais simples, não requer configuração de caminho do vault, apenas um botão de ativação. Porém, o Obsidian permite especificar pasta de destino e mais personalizações.</p></div><h2 id="passo-a-passo" tabindex="-1">Passo a Passo <a class="header-anchor" href="#passo-a-passo" aria-label="Permalink to &quot;Passo a Passo&quot;">​</a></h2><h3 id="passo-1-abrir-as-configuracoes-do-plannotator" tabindex="-1">Passo 1: Abrir as Configurações do Plannotator <a class="header-anchor" href="#passo-1-abrir-as-configuracoes-do-plannotator" aria-label="Permalink to &quot;Passo 1: Abrir as Configurações do Plannotator&quot;">​</a></h3><p>Quando o AI Agent gerar um plano e abrir a interface do Plannotator, clique no botão ⚙️ <strong>Settings</strong> no canto superior direito.</p><p><strong>Você deve ver</strong>: O painel de configurações aparece com várias opções</p><h3 id="passo-2-ativar-a-integracao-bear" tabindex="-1">Passo 2: Ativar a Integração Bear <a class="header-anchor" href="#passo-2-ativar-a-integracao-bear" aria-label="Permalink to &quot;Passo 2: Ativar a Integração Bear&quot;">​</a></h3><p>No painel de configurações, encontre a seção <strong>Bear Notes</strong> e clique no botão de alternância.</p><p><strong>Por quê</strong> O botão mudará de cinza (desativado) para azul (ativado) e será salvo no localStorage do navegador.</p><p><strong>Você deve ver</strong>:</p><ul><li>O botão Bear Notes fica azul</li><li>Texto descritivo: &quot;Auto-save approved plans to Bear&quot;</li></ul><h3 id="passo-3-aprovar-o-plano" tabindex="-1">Passo 3: Aprovar o Plano <a class="header-anchor" href="#passo-3-aprovar-o-plano" aria-label="Permalink to &quot;Passo 3: Aprovar o Plano&quot;">​</a></h3><p>Após concluir a revisão do plano, clique no botão <strong>Approve</strong> na parte inferior.</p><p><strong>Por quê</strong> O Plannotator lê as configurações do Bear e, se estiver ativado, chama o x-callback-url do Bear junto com a aprovação.</p><p><strong>Você deve ver</strong>:</p><ul><li>O aplicativo Bear abre automaticamente</li><li>Uma janela de nova nota aparece</li><li>Título e conteúdo já estão preenchidos</li><li>Tags já foram geradas (começando com <code>#</code>)</li></ul><h3 id="passo-4-verificar-a-nota-salva" tabindex="-1">Passo 4: Verificar a Nota Salva <a class="header-anchor" href="#passo-4-verificar-a-nota-salva" aria-label="Permalink to &quot;Passo 4: Verificar a Nota Salva&quot;">​</a></h3><p>No Bear, verifique a nota criada e confirme:</p><ul><li>O título está correto (extraído do H1 do plano)</li><li>O conteúdo está completo (inclui o plano inteiro)</li><li>As tags fazem sentido (nome do projeto, palavras-chave, linguagens de programação)</li></ul><p><strong>Você deve ver</strong>: Uma estrutura de nota semelhante a esta:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[Conteúdo completo do plano...]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#plannotator #myproject #authentication #typescript #api</span></span></code></pre></div><h2 id="checklist-✅" tabindex="-1">Checklist ✅ <a class="header-anchor" href="#checklist-✅" aria-label="Permalink to &quot;Checklist ✅&quot;">​</a></h2><ul><li>[ ] O botão Bear Notes está ativado nas Settings</li><li>[ ] O Bear abre automaticamente após aprovar o plano</li><li>[ ] O título da nota corresponde ao H1 do plano</li><li>[ ] A nota contém o conteúdo completo do plano</li><li>[ ] As tags incluem <code>#plannotator</code> e o nome do projeto</li></ul><h2 id="solucao-de-problemas" tabindex="-1">Solução de Problemas <a class="header-anchor" href="#solucao-de-problemas" aria-label="Permalink to &quot;Solução de Problemas&quot;">​</a></h2><h3 id="o-bear-nao-abre-automaticamente" tabindex="-1">O Bear Não Abre Automaticamente <a class="header-anchor" href="#o-bear-nao-abre-automaticamente" aria-label="Permalink to &quot;O Bear Não Abre Automaticamente&quot;">​</a></h3><p><strong>Causa</strong>: O comando <code>open</code> do sistema falhou, possivelmente porque:</p><ul><li>O Bear não está instalado ou não foi baixado da App Store</li><li>O URL scheme do Bear foi sequestrado por outro aplicativo</li></ul><p><strong>Solução</strong>:</p><ol><li>Confirme que o Bear está instalado corretamente</li><li>Teste manualmente no terminal: <code>open &quot;bear://x-callback-url/create?title=test&quot;</code></li></ol><h3 id="tags-nao-sao-as-esperadas" tabindex="-1">Tags Não São as Esperadas <a class="header-anchor" href="#tags-nao-sao-as-esperadas" aria-label="Permalink to &quot;Tags Não São as Esperadas&quot;">​</a></h3><p><strong>Causa</strong>: As tags são geradas automaticamente seguindo estas regras:</p><ul><li>Obrigatória: <code>#plannotator</code></li><li>Obrigatória: nome do projeto (extraído do nome do repositório git ou diretório)</li><li>Opcional: até 3 palavras-chave extraídas do título H1 (excluindo stopwords)</li><li>Opcional: tags de linguagem de programação extraídas dos blocos de código (excluindo json/yaml/markdown)</li><li>Máximo de 7 tags</li></ul><p><strong>Solução</strong>:</p><ul><li>Se as tags não estiverem corretas, você pode editá-las manualmente no Bear</li><li>Se o nome do projeto estiver errado, verifique a configuração do repositório git ou o nome do diretório</li></ul><h3 id="plano-aprovado-mas-nao-salvo" tabindex="-1">Plano Aprovado Mas Não Salvo <a class="header-anchor" href="#plano-aprovado-mas-nao-salvo" aria-label="Permalink to &quot;Plano Aprovado Mas Não Salvo&quot;">​</a></h3><p><strong>Causa</strong>:</p><ul><li>O botão Bear não está ativado (verifique nas Settings)</li><li>Erro de rede ou timeout na resposta do Bear</li><li>Conteúdo do plano está vazio</li></ul><p><strong>Solução</strong>:</p><ol><li>Confirme que o botão nas Settings está azul (ativado)</li><li>Verifique se há logs de erro no terminal (<code>[Bear] Save failed:</code>)</li><li>Aprove o plano novamente</li></ol><h2 id="detalhes-do-mecanismo-de-geracao-de-tags" tabindex="-1">Detalhes do Mecanismo de Geração de Tags <a class="header-anchor" href="#detalhes-do-mecanismo-de-geracao-de-tags" aria-label="Permalink to &quot;Detalhes do Mecanismo de Geração de Tags&quot;">​</a></h2><p>O Plannotator gera tags inteligentemente para que você possa encontrar planos rapidamente no Bear. Aqui estão as regras de geração:</p><table tabindex="0"><thead><tr><th>Origem da Tag</th><th>Exemplo</th><th>Prioridade</th></tr></thead><tbody><tr><td>Tag fixa</td><td><code>#plannotator</code></td><td>Obrigatória</td></tr><tr><td>Nome do projeto</td><td><code>#myproject</code>, <code>#plannotator</code></td><td>Obrigatória</td></tr><tr><td>Palavras-chave do H1</td><td><code>#authentication</code>, <code>#api</code></td><td>Opcional (máx. 3)</td></tr><tr><td>Linguagem de programação</td><td><code>#typescript</code>, <code>#python</code></td><td>Opcional</td></tr></tbody></table><p><strong>Lista de stopwords</strong> (não se tornam tags):</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p><strong>Linguagens excluídas</strong> (não se tornam tags):</p><ul><li><code>json</code>, <code>yaml</code>, <code>yml</code>, <code>text</code>, <code>txt</code>, <code>markdown</code>, <code>md</code></li></ul><details class="details custom-block"><summary>Exemplo: Processo de Geração de Tags</summary><p>Suponha que o título do plano seja &quot;Implementation Plan: User Authentication System in TypeScript&quot; e os blocos de código contenham Python e JSON:</p><ol><li><strong>Tag fixa</strong>: <code>#plannotator</code></li><li><strong>Nome do projeto</strong>: <code>#myproject</code> (assumindo o nome do repositório git)</li><li><strong>Palavras-chave do H1</strong>: <ul><li><code>implementation</code> → excluída (stopword)</li><li><code>plan</code> → excluída (stopword)</li><li><code>user</code> → mantida → <code>#user</code></li><li><code>authentication</code> → mantida → <code>#authentication</code></li><li><code>system</code> → mantida → <code>#system</code></li><li><code>typescript</code> → mantida → <code>#typescript</code></li></ul></li><li><strong>Linguagens de programação</strong>: <ul><li><code>python</code> → mantida → <code>#python</code></li><li><code>json</code> → excluída (lista de exclusão)</li></ul></li></ol><p>Tags finais: <code>#plannotator #myproject #user #authentication #system #typescript #python</code> (7 tags, limite atingido)</p></details><h2 id="comparacao-com-a-integracao-obsidian" tabindex="-1">Comparação com a Integração Obsidian <a class="header-anchor" href="#comparacao-com-a-integracao-obsidian" aria-label="Permalink to &quot;Comparação com a Integração Obsidian&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Integração Bear</th><th>Integração Obsidian</th></tr></thead><tbody><tr><td>Complexidade de configuração</td><td>Simples (apenas um botão)</td><td>Média (precisa escolher vault e pasta)</td></tr><tr><td>Armazenamento</td><td>Dentro do app Bear</td><td>Caminho do vault especificado</td></tr><tr><td>Nome do arquivo</td><td>Gerenciado automaticamente pelo Bear</td><td><code>Title - Mon D, YYYY H-MMam.md</code></td></tr><tr><td>Frontmatter</td><td>Não (Bear não suporta)</td><td>Sim (created, source, tags)</td></tr><tr><td>Multiplataforma</td><td>Apenas macOS</td><td>macOS/Windows/Linux</td></tr><tr><td>x-callback-url</td><td>✅ Usa</td><td>❌ Escreve arquivo diretamente</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Como Escolher</p><ul><li>Se você usa apenas macOS e gosta do Bear: a integração Bear é mais simples</li><li>Se precisa de multiplataforma ou caminhos de armazenamento personalizados: a integração Obsidian é mais flexível</li><li>Se quiser usar ambos: você pode ativar os dois (aprovar um plano salvará em ambos os lugares)</li></ul></div><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><ul><li>A integração Bear funciona através do protocolo x-callback-url, com configuração simples</li><li>Basta ativar o botão nas Settings, sem necessidade de especificar caminhos</li><li>Salva automaticamente no Bear ao aprovar o plano</li><li>Tags geradas inteligentemente, incluindo nome do projeto, palavras-chave e linguagens de programação (máximo de 7)</li><li>Comparada à integração Obsidian, a do Bear é mais simples mas com menos recursos</li></ul><h2 id="previa-da-proxima-licao" tabindex="-1">Prévia da Próxima Lição <a class="header-anchor" href="#previa-da-proxima-licao" aria-label="Permalink to &quot;Prévia da Próxima Lição&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos sobre o <strong><a href="./../remote-mode/">Modo Remoto/Devcontainer</a></strong>.</p><p>Você aprenderá:</p><ul><li>Como usar o Plannotator em ambientes remotos (SSH, devcontainer, WSL)</li><li>Configurar portas fixas e encaminhamento de portas</li><li>Abrir o navegador em ambiente remoto para visualizar a página de revisão</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código-Fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código-Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Interface de configuração Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L18-L20" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>18-20</td></tr><tr><td>Salvar no Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L234-L257" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>234-257</td></tr><tr><td>Extração de tags</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>Extração de título</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L94-L105" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>94-105</td></tr><tr><td>Interface de configurações Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L15-L17" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>15-17</td></tr><tr><td>Ler configurações Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L22-L26" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>22-26</td></tr><tr><td>Salvar configurações Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L31-L33" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>31-33</td></tr><tr><td>Componente UI de configurações</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L496-L518" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>496-518</td></tr><tr><td>Chamar Bear ao aprovar</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L512-L514" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>512-514</td></tr><tr><td>Servidor processa Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L250-L257" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>250-257</td></tr></tbody></table><p><strong>Funções principais</strong>:</p><ul><li><code>saveToBear(config: BearConfig)</code>: Salva o plano no Bear via x-callback-url</li><li><code>extractTags(markdown: string)</code>: Extrai tags inteligentemente do conteúdo do plano (máximo de 7)</li><li><code>extractTitle(markdown: string)</code>: Extrai o título da nota do H1 do plano</li><li><code>getBearSettings()</code>: Lê as configurações de integração Bear do localStorage</li><li><code>saveBearSettings(settings)</code>: Salva as configurações de integração Bear no localStorage</li></ul><p><strong>Constantes principais</strong>:</p><ul><li><code>STORAGE_KEY_ENABLED = &#39;plannotator-bear-enabled&#39;</code>: Nome da chave das configurações Bear no localStorage</li></ul><p><strong>Formato da URL Bear</strong>:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bear</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//x-callback-url/create?title={title}&amp;text={content}&amp;open_note=no</span></span></code></pre></div></details>`,75)])])}const g=o(i,[["render",n]]);export{m as __pageData,g as default};
